const body = $input.first().json.body || $input.first().json;
if (!body.client_id) throw new Error('Missing required field: client_id');
return [{ json: { client_id: body.client_id, pipeline_run_id: body.pipeline_run_id || null, started_at: new Date().toISOString() } }];

// Check cost ceiling before starting expensive SerpAPI calls
const client = ($('Fetch_Client_Config').first().json || [])[0];
const clusters = $input.first().json || [];
const ctx = $('Validate_Score_Payload').first().json;

const budget = client?.config?.monthly_api_budget_usd || 50;
const runsPerMonth = client?.config?.expected_runs_per_month || 4;
const ceilingPct = client?.config?.per_run_cost_ceiling_pct || 150;
const perRunCeiling = (budget / runsPerMonth) * (ceilingPct / 100);

// SerpAPI costs ~$0.01 per search, we do 3 per cluster, cap at 100 clusters
const maxClusters = Math.min(100, clusters.length);
const estimatedCost = maxClusters * 3 * 0.01;

if (estimatedCost > perRunCeiling) {
  throw new Error(`Cost ceiling would be exceeded: estimated $${estimatedCost.toFixed(2)} > ceiling $${perRunCeiling.toFixed(2)}. Reduce cluster count or increase budget.`);
}

return clusters.slice(0, maxClusters).map(cluster => ({
  json: {
    ...ctx,
    client_config: client?.config || {},
    cluster_id: cluster.id,
    head_term: cluster.canonical_head_term,
    theme_label: cluster.theme_label,
    suggested_service_pillar: cluster.suggested_service_pillar,
    pillar_assignment_confidence: cluster.pillar_assignment_confidence || 0,
    content_theme: cluster.content_theme,
    keyword_count: cluster.keyword_count || 0,
    cannibalization_risk_page_id: cluster.cannibalization_risk_page_id
  }
}));

// Parse SERP results and build LLM ICP scoring request
const ctx = $('Check_Cost_Ceiling').item.json;
const serpData = $input.first().json;

const organicResults = (serpData?.organic_results || []).slice(0, 3).map(r => ({
  title: r.title || '',
  snippet: r.snippet || '',
  link: r.link || ''
}));

return [{
  json: {
    ...ctx,
    serp_results: organicResults,
    llm_request: {
      model: 'google/gemini-2.0-flash-001',
      messages: [
        {
          role: 'system',
          content: 'You are an expert SEO strategist scoring a keyword cluster for B2B ICP fit. Return ONLY raw JSON with: icp_match_score (0-1), icp_match_reasoning, commercial_intent_weight (number per the scale), serp_intent_signals (array of strings), priority_score_inputs object.'
        },
        {
          role: 'user',
          content: `Score this cluster:\n\nHead term: ${ctx.head_term}\nTheme: ${ctx.theme_label}\nContent theme: ${ctx.content_theme}\n\nSERP results:\n${JSON.stringify(organicResults, null, 2)}\n\nICP persona: ${ctx.client_config?.icp_persona || ''}\n\nCommercial intent scale: transactional=5, commercial_investigation=3, navigational_branded=4, local=4, informational=1, navigational_other=0, navigational_competitor=-10\n\nReturn: icp_match_score, icp_match_reasoning, commercial_intent_weight, serp_intent_signals, priority_score_inputs (with pillar_match_bonus=1 if pillar assigned else 0, cannibalization_risk_penalty=1 if risk flag else 0).`
        }
      ],
      response_format: { type: 'json_object' },
      temperature: 0.1,
      max_tokens: 512
    }
  }
}];

// Compute final priority_score and update cluster
const ctx = $('Build_ICP_Request').item.json;
const llmRaw = $input.first().json;

let scoring = {};
try {
  scoring = JSON.parse(llmRaw.choices?.[0]?.message?.content || '{}');
} catch(e) {
  scoring = { icp_match_score: 0.5, commercial_intent_weight: 1 };
}

const inputs = scoring.priority_score_inputs || {};
const commercial = scoring.commercial_intent_weight || inputs.commercial_intent_weight || 1;
const icpScore = scoring.icp_match_score || 0.5;
const totalVolume = ctx.keyword_count || 1; // Proxy since we don't have volume aggregated here
const avgKd = 0; // Would need to join keyword_classifications — use 0 as safe default
const pillarBonus = (ctx.suggested_service_pillar && ctx.pillar_assignment_confidence > 0.5) ? 1 : 0;
const nicheBonus = inputs.niche_focus_bonus || 0;
const cannibalPenalty = ctx.cannibalization_risk_page_id ? 1 : 0;

const priorityScore = (commercial * 5)
  + (icpScore * 3)
  + (Math.log(totalVolume + 1) * 1)
  - (avgKd * 0.5)
  + (pillarBonus * 1.5)
  + (nicheBonus * 1)
  - (cannibalPenalty * 3);

const inputTokens = llmRaw.usage?.prompt_tokens || 0;
const outputTokens = llmRaw.usage?.completion_tokens || 0;

return [{
  json: {
    client_id: ctx.client_id,
    pipeline_run_id: ctx.pipeline_run_id,
    cluster_id: ctx.cluster_id,
    priority_score: Math.round(priorityScore * 100) / 100,
    icp_match_score: icpScore,
    commercial_intent_weight: commercial,
    llm_tokens: { input: inputTokens, output: outputTokens },
    serp_cost: 3 * 0.01
  }
}];
